import yargs from "yargs";
import { hideBin } from "yargs/helpers";
import { promptFoundryUrl } from "./prompts/promptFoundryUrl.js";
import { promptOsdkPackage } from "./prompts/promptOsdkPackage.js";
import { promptOsdkRegistryUrl } from "./prompts/promptOsdkRegistryUrl.js";
import { promptOverwrite } from "./prompts/promptOverwrite.js";
import { promptProject } from "./prompts/promptProject.js";
import { promptSdkVersion } from "./prompts/promptSdkVersion.js";
import { promptTemplate } from "./prompts/promptTemplate.js";
import { promptWidgetSetRid } from "./prompts/promptWidgetSetRid.js";
import { run } from "./run.js";
export async function cli(args = process.argv) {
  const base = yargs(hideBin(args)).version(process.env.PACKAGE_VERSION ?? "").wrap(Math.min(150, yargs().terminalWidth())).strict().help().command("$0 [project] [--<option>]", "Create a new OSDK widget set based on framework templates. Information may be provided through options to skip interactive prompts.", yargs => yargs.positional("project", {
    type: "string",
    describe: "Project name to create"
  }).option("overwrite", {
    type: "boolean",
    describe: "Overwrite project directory if already exists"
  }).option("beta", {
    type: "boolean",
    describe: "Use templates compatible with the Beta version of the SDK"
  }).option("template", {
    type: "string",
    describe: "Template name to use"
  }).option("sdkVersion", {
    type: "string",
    describe: "The OSDK version to use"
  }).option("foundryUrl", {
    type: "string",
    describe: "URL for the Foundry stack"
  }).option("widgetSet", {
    type: "string",
    describe: "Widget set resource identifier (rid)"
  }).option("osdkPackage", {
    type: "string",
    describe: "OSDK package name for application"
  }).option("osdkRegistryUrl", {
    type: "string",
    describe: "URL for NPM registry to install OSDK package"
  }));
  const parsed = base.parseSync();
  const project = await promptProject(parsed);
  const overwrite = await promptOverwrite({
    ...parsed,
    project
  });
  const template = await promptTemplate(parsed);
  const sdkVersion = await promptSdkVersion({
    ...parsed,
    template
  });
  const foundryUrl = await promptFoundryUrl(parsed);
  const osdkPackage = template.requiresOsdk ? await promptOsdkPackage(parsed) : undefined;
  const osdkRegistryUrl = template.requiresOsdk ? await promptOsdkRegistryUrl(parsed) : undefined;
  const widgetSet = await promptWidgetSetRid(parsed);
  await run({
    project,
    overwrite,
    template,
    sdkVersion,
    foundryUrl,
    widgetSet,
    osdkPackage,
    osdkRegistryUrl
  });
}